using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Paging;using verii_metivon_api.Core.UnitOfWork;using verii_metivon_api.Modules.Pricing.Application.Parameters;using verii_metivon_api.Modules.Pricing.Domain.Entities;
namespace verii_metivon_api.Modules.Pricing.Application.Services;
public sealed class PricingQuery:PagedQuery{public bool?IsActive{get;init;}}public sealed record PriceListRow(long Id,string Code,string Name,string Currency,DateOnly ValidFrom,DateOnly?ValidTo,int Priority,bool IsDefault,bool IsActive);public sealed record SavePriceListRequest(string Code,string Name,string?Description,long CurrencyId,DateOnly ValidFrom,DateOnly?ValidTo,bool PricesIncludeTax,int Priority,bool IsDefault,bool IsActive);public sealed record SavePriceListLineRequest(long ProductId,long UnitId,long?CustomerGroupId,decimal MinimumQuantity,decimal UnitPrice,DateOnly?ValidFrom,DateOnly?ValidTo,bool IsActive);public sealed record PriceRequest(long ProductId,long UnitId,long?BusinessPartnerId,long?CustomerGroupId,decimal Quantity,DateOnly Date,long?BranchId=null);public sealed record PriceResult(decimal UnitPrice,decimal DiscountRate,decimal DiscountAmount,long?PriceListLineId,long?DiscountRuleId);
public interface IPricingService{Task<ApiResponse<PagedResult<PriceListRow>>>GetPagedAsync(PricingQuery q,CancellationToken ct);Task<ApiResponse<SavePriceListRequest>>GetAsync(long id,CancellationToken ct);Task<ApiResponse<object>>CreateAsync(SavePriceListRequest r,CancellationToken ct);Task<ApiResponse<object>>UpdateAsync(long id,SavePriceListRequest r,CancellationToken ct);Task<ApiResponse<object>>DeleteAsync(long id,CancellationToken ct);Task<ApiResponse<object>>AddLineAsync(long id,SavePriceListLineRequest r,CancellationToken ct);Task<ApiResponse<PriceResult>>CalculateAsync(PriceRequest r,CancellationToken ct);}
public sealed class PricingService(IUnitOfWork u,IPricingParameterService parameters):IPricingService
{
 public async Task<ApiResponse<SavePriceListRequest>>GetAsync(long id,CancellationToken ct){var e=await u.Repository<PriceList>().GetByIdAsync(id,ct);return e is null?ApiResponse<SavePriceListRequest>.Error("Price list not found.",404):ApiResponse<SavePriceListRequest>.Ok(new(e.Code,e.Name,e.Description,e.CurrencyId,e.ValidFrom,e.ValidTo,e.PricesIncludeTax,e.Priority,e.IsDefault,e.IsActive));}
 public async Task<ApiResponse<object>>UpdateAsync(long id,SavePriceListRequest r,CancellationToken ct){var e=await u.Repository<PriceList>().GetByIdForUpdateAsync(id,ct);if(e is null)return ApiResponse<object>.Error("Price list not found.",404);var code=r.Code.Trim().ToUpperInvariant();if(string.IsNullOrWhiteSpace(code)||string.IsNullOrWhiteSpace(r.Name))return ApiResponse<object>.Error("Price list code and name are required.",400);if(r.ValidTo.HasValue&&r.ValidTo<r.ValidFrom)return ApiResponse<object>.Error("Price list end date cannot be earlier than start date.",400);if(await u.Repository<PriceList>().ExistsAsync(x=>x.Id!=id&&x.Code==code,ct))return ApiResponse<object>.Error("Price list code exists.",409);await u.ExecuteInTransactionAsync(async t=>{if(r.IsDefault){var old=await u.Repository<PriceList>().Query(true).Where(x=>x.Id!=id&&x.IsDefault).ToListAsync(t);old.ForEach(x=>x.IsDefault=false);}e.Code=code;e.Name=r.Name.Trim();e.Description=r.Description?.Trim();e.CurrencyId=r.CurrencyId;e.ValidFrom=r.ValidFrom;e.ValidTo=r.ValidTo;e.PricesIncludeTax=r.PricesIncludeTax;e.Priority=r.Priority;e.IsDefault=r.IsDefault;e.IsActive=r.IsActive;await u.SaveChangesAsync(t);},ct);return ApiResponse<object>.Ok(new{e.Id});}
 public async Task<ApiResponse<object>>DeleteAsync(long id,CancellationToken ct){var e=await u.Repository<PriceList>().GetByIdForUpdateAsync(id,ct);if(e is null)return ApiResponse<object>.Error("Price list not found.",404);if(e.IsDefault)return ApiResponse<object>.Error("Default price list cannot be deleted.",409);if(await u.Repository<PriceListLine>().ExistsAsync(x=>x.PriceListId==id,ct))return ApiResponse<object>.Error("Price list has lines and cannot be deleted.",409);u.Repository<PriceList>().Remove(e);await u.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id});}
 public async Task<ApiResponse<PagedResult<PriceListRow>>>GetPagedAsync(PricingQuery q,CancellationToken ct){var x=u.Repository<PriceList>().Query().Include(v=>v.Currency).AsQueryable();if(q.IsActive.HasValue)x=x.Where(v=>v.IsActive==q.IsActive);if(!string.IsNullOrWhiteSpace(q.Search)){var s=q.Search.Trim();x=x.Where(v=>v.Code.Contains(s)||v.Name.Contains(s));}x=x.ApplyPagedFilters(q);var total=await x.CountAsync(ct);var rows=await x.OrderBy(v=>v.DisplayOrder).ThenBy(v=>v.Code).Skip((q.NormalizedPageNumber-1)*q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v=>new PriceListRow(v.Id,v.Code,v.Name,v.Currency.Code,v.ValidFrom,v.ValidTo,v.Priority,v.IsDefault,v.IsActive)).ToListAsync(ct);return ApiResponse<PagedResult<PriceListRow>>.Ok(new(rows,q.NormalizedPageNumber,q.NormalizedPageSize,total));}
 public async Task<ApiResponse<object>>CreateAsync(SavePriceListRequest r,CancellationToken ct){if(string.IsNullOrWhiteSpace(r.Code)||string.IsNullOrWhiteSpace(r.Name))return ApiResponse<object>.Error("Price list code and name are required.",400);if(r.ValidTo.HasValue&&r.ValidTo<r.ValidFrom)return ApiResponse<object>.Error("Price list end date cannot be earlier than start date.",400);var code=r.Code.Trim().ToUpperInvariant();if(await u.Repository<PriceList>().ExistsAsync(x=>x.Code==code,ct))return ApiResponse<object>.Error("Price list code exists.",409);var e=new PriceList{Code=code,Name=r.Name.Trim(),Description=r.Description,CurrencyId=r.CurrencyId,ValidFrom=r.ValidFrom,ValidTo=r.ValidTo,PricesIncludeTax=r.PricesIncludeTax,Priority=r.Priority,IsDefault=r.IsDefault,IsActive=r.IsActive};await u.ExecuteInTransactionAsync(async t=>{if(e.IsDefault){var old=await u.Repository<PriceList>().Query(true).Where(x=>x.IsDefault).ToListAsync(t);old.ForEach(x=>x.IsDefault=false);}await u.Repository<PriceList>().AddAsync(e,t);await u.SaveChangesAsync(t);},ct);return ApiResponse<object>.Ok(new{e.Id});}
 public async Task<ApiResponse<object>>AddLineAsync(long id,SavePriceListLineRequest r,CancellationToken ct){if(!await u.Repository<PriceList>().ExistsAsync(x=>x.Id==id,ct))return ApiResponse<object>.Error("Price list not found.",404);var p=await parameters.ResolveSettingsAsync(null,ct);if(r.MinimumQuantity<0||r.UnitPrice<0||(!p.AllowZeroPrice&&r.UnitPrice==0))return ApiResponse<object>.Error("Minimum quantity or unit price is invalid.",400);if(r.ValidFrom.HasValue&&r.ValidTo.HasValue&&r.ValidTo<r.ValidFrom)return ApiResponse<object>.Error("Price line end date cannot be earlier than start date.",400);if(!p.AllowPriceListOverlap&&await u.Repository<PriceListLine>().ExistsAsync(x=>x.PriceListId==id&&x.ProductId==r.ProductId&&x.UnitId==r.UnitId&&x.CustomerGroupId==r.CustomerGroupId&&(x.ValidTo==null||r.ValidFrom==null||x.ValidTo>=r.ValidFrom)&&(r.ValidTo==null||x.ValidFrom==null||x.ValidFrom<=r.ValidTo),ct))return ApiResponse<object>.Error("An overlapping price line already exists.",409);var e=new PriceListLine{PriceListId=id,ProductId=r.ProductId,UnitId=r.UnitId,CustomerGroupId=r.CustomerGroupId,MinimumQuantity=r.MinimumQuantity,UnitPrice=r.UnitPrice,ValidFrom=r.ValidFrom,ValidTo=r.ValidTo,IsActive=r.IsActive};await u.Repository<PriceListLine>().AddAsync(e,ct);await u.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id});}
 public async Task<ApiResponse<PriceResult>>CalculateAsync(PriceRequest r,CancellationToken ct){if(r.Quantity<=0)return ApiResponse<PriceResult>.Error("Quantity must be positive.",400);var p=await parameters.ResolveSettingsAsync(r.BranchId,ct);var candidates=await u.Repository<PriceListLine>().Query().Include(x=>x.PriceList).Where(x=>x.IsActive&&x.PriceList.IsActive&&x.ProductId==r.ProductId&&x.UnitId==r.UnitId&&x.MinimumQuantity<=r.Quantity&&x.PriceList.ValidFrom<=r.Date&&(x.PriceList.ValidTo==null||x.PriceList.ValidTo>=r.Date)&&(x.ValidFrom==null||x.ValidFrom<=r.Date)&&(x.ValidTo==null||x.ValidTo>=r.Date)&&(x.CustomerGroupId==null||x.CustomerGroupId==r.CustomerGroupId)).ToListAsync(ct);if(!p.FallbackToDefaultPriceList)candidates=candidates.Where(x=>!x.PriceList.IsDefault||(r.CustomerGroupId.HasValue&&x.CustomerGroupId==r.CustomerGroupId)).ToList();IOrderedEnumerable<PriceListLine> ordered=p.PreferCustomerGroupPrice?candidates.OrderByDescending(x=>x.CustomerGroupId.HasValue):candidates.OrderBy(x=>x.CustomerGroupId.HasValue);ordered=p.PreferHigherMinimumQuantity?ordered.ThenByDescending(x=>x.MinimumQuantity):ordered.ThenBy(x=>x.MinimumQuantity);ordered=p.PreferHigherPriceListPriority?ordered.ThenByDescending(x=>x.PriceList.Priority):ordered.ThenBy(x=>x.PriceList.Priority);var line=ordered.ThenByDescending(x=>x.PriceList.IsDefault).FirstOrDefault();if(line is null)return ApiResponse<PriceResult>.Error("Applicable price not found.",404);var unitPrice=Round(line.UnitPrice,p.PriceRoundingDecimals,p.RoundingMethod);if(!p.AllowZeroPrice&&unitPrice==0)return ApiResponse<PriceResult>.Error("Applicable price is zero and zero pricing is disabled.",400);var rules=await u.Repository<DiscountRule>().Query().Where(x=>x.IsActive&&x.ValidFrom<=r.Date&&(x.ValidTo==null||x.ValidTo>=r.Date)&&x.MinimumQuantity<=r.Quantity&&(x.BusinessPartnerId==null||x.BusinessPartnerId==r.BusinessPartnerId)&&(x.CustomerGroupId==null||x.CustomerGroupId==r.CustomerGroupId)&&(x.ProductId==null||x.ProductId==r.ProductId)).OrderByDescending(x=>x.Priority).Take(p.MaximumDiscountRulesApplied).ToListAsync(ct);if(!p.AllowMultipleDiscounts&&rules.Count>1)rules=rules.Take(1).ToList();var gross=unitPrice*r.Quantity;var remaining=gross;decimal discount=0;long?firstRuleId=null;foreach(var rule in rules){firstRuleId??=rule.Id;decimal current;if(rule.DiscountAmount.HasValue&&p.AllowFixedAmountDiscount)current=rule.DiscountAmount.Value;else current=remaining*(rule.DiscountRate??0)/100m;if(rule.MaximumDiscountAmount is decimal max&&current>max)current=max;if(current<0)current=0;if(current>remaining)current=remaining;discount+=current;remaining-=current;if(rule.IsExclusive&&p.StopAtExclusiveDiscount)break;}var maximum=gross*p.MaximumTotalDiscountPercent/100m;if(discount>maximum)discount=maximum;discount=Round(discount,p.DiscountRoundingDecimals,p.RoundingMethod);var rate=gross==0?0:Math.Round(discount/gross*100m,6,MidpointRounding.AwayFromZero);return ApiResponse<PriceResult>.Ok(new(unitPrice,rate,discount,line.Id,firstRuleId));}
 static decimal Round(decimal value,int decimals,int method){if(method==0)return Math.Round(value,decimals,MidpointRounding.ToEven);if(method==1)return Math.Round(value,decimals,MidpointRounding.AwayFromZero);decimal factor=1;for(var i=0;i<decimals;i++)factor*=10;return method==2?Math.Floor(value*factor)/factor:Math.Ceiling(value*factor)/factor;}
}


